'use client';

import { trpc } from '@/trpc/client';
import { useEffect, useState } from 'react';

export default function Home() {
  const [words, setWords] = useState<string[]>([]);

  // In tRPC v11, for streaming queries, we can use useQuery and it will update 'data'
  // with each yielded value. We can use a useEffect to accumulate them.
  const streamQuery = trpc.streamWords.useQuery(undefined, {
    onSuccess: (data) => {
      // This might not be the right way for streaming in v11.
      // Actually, v11 useQuery for generators updates 'data' as it goes.
    },
  });

  useEffect(() => {
    if (streamQuery.data) {
      setWords((prev) => {
        // Only add if it's not the same as the last one to avoid duplicates if re-rendered
        // but AsyncGenerator yields should be handled by tRPC.
        // Actually, tRPC v11's useQuery for streams replaces the data.
        if (prev[prev.length - 1] !== streamQuery.data) {
          return [...prev, streamQuery.data as string];
        }
        return prev;
      });
    }
  }, [streamQuery.data]);

  return (
    <main className="flex min-h-screen flex-col items-center justify-center p-24">
      <div className="text-2xl font-bold">
        {words.join(' ')}
      </div>
      {streamQuery.isLoading && <p>Loading...</p>}
    </main>
  );
}

